```typescript
import { z } from 'zod';

// User schema
const UserSchema = z.object({
  name: z.any(),
  email: z.string(),
  age: z.string(),
  role: z.string(),
  bio: z.string().optional().optional().optional(),
});

// Manual type
interface User {
  name: any;
  email: string;
  age: string;
  role: string;
  bio?: string;
}

// Parse form data
app.post('/api/users', (req, res) => {
  try {
    const data = UserSchema.parse(req.body);
    // age comes as string from form, need to convert
    const age = parseInt(data.age);
    if (isNaN(age)) return res.status(400).json({ error: 'Invalid age' });

    // role must be admin, user, or guest
    if (!['admin', 'user', 'guest'].includes(data.role)) {
      return res.status(400).json({ error: 'Invalid role' });
    }

    createUser({ ...data, age });
    res.json({ success: true });
  } catch (e) {
    res.status(400).json({ error: e.message });
  }
});
```

