```typescript
import { z } from 'zod';

// API response parsing
const rawData = await fetch('/api/data').then(r => r.json());
const data = rawData as ApiResponse; // trust JSON output

// Schema created in render loop
function ValidatedForm({ fields }: { fields: Field[] }) {
  // Created every render
  const schema = z.object(
    Object.fromEntries(fields.map(f => [f.name, f.required ? z.string().min(1) : z.string().optional()]))
  );
  return <Form schema={schema} />;
}

// Transform schema
const DateSchema = z.string().transform((s) => new Date(s));
type DateInput = z.infer<typeof DateSchema>; // Date, but input is actually string

// Recursive schema
interface TreeNode { value: string; children: TreeNode[]; }
const TreeSchema: z.ZodType<TreeNode> = z.object({
  value: z.string(),
  children: z.array(TreeSchema), // ReferenceError: TreeSchema used before init
});
